+        EndText: Text;
+        StartValue: Integer;
+        EndValue: Integer;
+        RemainingFilter: Text;
+    begin
+        if ContractEntryNoFilter = '' then
+            exit;
+
+        RemainingFilter := ContractEntryNoFilter;
+        ContractEntryNoFilter := '';
+        while RemainingFilter <> '' do begin
+            RangePos := StrPos(RemainingFilter, '|');
+            if RangePos > 0 then begin
+                FilterSegment := CopyStr(RemainingFilter, 1, RangePos - 1);
+                RemainingFilter := CopyStr(RemainingFilter, RangePos + 1);
+            end else begin
+                FilterSegment := RemainingFilter;
+                RemainingFilter := '';
+            end;
+
+            RangePos := StrPos(FilterSegment, '..');
+            if RangePos > 0 then begin
+                StartText := CopyStr(FilterSegment, 1, RangePos - 1);
+                EndText := CopyStr(FilterSegment, RangePos + 2);
+                if (StartText <> '') and (EndText <> '') and
+                   Evaluate(StartValue, StartText) and Evaluate(EndValue, EndText) then
+                    if StartValue > EndValue then
+                        FilterSegment := Format(EndValue) + '..' + Format(StartValue);
+            end;
+
+            if ContractEntryNoFilter <> '' then
+                ContractEntryNoFilter += '|';
+            ContractEntryNoFilter += FilterSegment;
+        end;
+    end;
